{"parts":[{"tool_name":"read_file","content":["@import "tailwindcss";
@import "tw-animate-css";
@plugin "@tailwindcss/typography";

@custom-variant dark (&:is(.dark *));

:root {
  color-scheme: light dark;
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;

  /* Arsenal Brand Colors */
  --arsenal-red: #EF0107;
  --arsenal-gold: #9C824A;
  --arsenal-navy: #063672;
  --arsenal-white: #FFFFFF;
  --arsenal-dark: #1a1a1a;
  --arsenal-red-glow: rgba(239, 1, 7, 0.3);
  --arsenal-gold-glow: rgba(156, 130, 74, 0.3);

  --radius: 0.625rem;
  --background: oklch(1 0 0);
  --foreground: oklch(0.147 0.004 49.25);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.147 0.004 49.25);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.147 0.004 49.25);
  --primary: oklch(0.216 0.006 56.043);
  --primary-foreground: oklch(0.985 0.001 106.423);
  --secondary: oklch(0.97 0.001 106.424);
  --secondary-foreground: oklch(0.216 0.006 56.043);
  --muted: oklch(0.97 0.001 106.424);
  --muted-foreground: oklch(0.553 0.013 58.071);
  --accent: oklch(0.97 0.001 106.424);
  --accent-foreground: oklch(0.216 0.006 56.043);
  --destructive: oklch(0.577 0.245 27.325);
  --border: oklch(0.923 0.003 48.717);
  --input: oklch(0.923 0.003 48.717);
  --ring: oklch(0.709 0.01 56.259);
  --chart-1: oklch(0.646 0.222 41.116);
  --chart-2: oklch(0.6 0.118 184.704);
  --chart-3: oklch(0.398 0.07 227.392);
  --chart-4: oklch(0.828 0.189 84.429);
  --chart-5: oklch(0.769 0.188 70.08);
  --sidebar: oklch(0.985 0.001 106.423);
  --sidebar-foreground: oklch(0.147 0.004 49.25);
  --sidebar-primary: oklch(0.216 0.006 56.043);
  --sidebar-primary-foreground: oklch(0.985 0.001 106.423);
  --sidebar-accent: oklch(0.97 0.001 106.424);
  --sidebar-accent-foreground: oklch(0.216 0.006 56.043);
  --sidebar-border: oklch(0.923 0.003 48.717);
  --sidebar-ring: oklch(0.709 0.01 56.259);
}

.dark {
  --background: #0d0d0d;
  --foreground: oklch(0.985 0.001 106.423);
  --card: #1a1a1a;
  --card-foreground: oklch(0.985 0.001 106.423);
  --popover: #1a1a1a;
  --popover-foreground: oklch(0.985 0.001 106.423);
  --primary: #EF0107;
  --primary-foreground: #ffffff;
  --secondary: #9C824A;
  --secondary-foreground: #ffffff;
  --muted: #2a2a2a;
  --muted-foreground: oklch(0.709 0.01 56.259);
  --accent: #063672;
  --accent-foreground: oklch(0.985 0.001 106.423);
  --destructive: oklch(0.704 0.191 22.216);
  --border: rgba(239, 1, 7, 0.15);
  --input: oklch(1 0 0 / 15%);
  --ring: #EF0107;
  --chart-1: #EF0107;
  --chart-2: #9C824A;
  --chart-3: #063672;
  --chart-4: #ff4d52;
  --chart-5: #c9a962;
  --sidebar: #1a1a1a;
  --sidebar-foreground: oklch(0.985 0.001 106.423);
  --sidebar-primary: #EF0107;
  --sidebar-primary-foreground: oklch(0.985 0.001 106.423);
  --sidebar-accent: #2a2a2a;
  --sidebar-accent-foreground: oklch(0.985 0.001 106.423);
  --sidebar-border: rgba(239, 1, 7, 0.15);
  --sidebar-ring: #EF0107;
}

body {
  margin: 0;
}

/* Arsenal-specific utility classes */
.arsenal-glow-red {
  box-shadow: 0 0 20px var(--arsenal-red-glow);
}

.arsenal-glow-gold {
  box-shadow: 0 0 20px var(--arsenal-gold-glow);
}

.arsenal-border {
  border: 1px solid rgba(239, 1, 7, 0.2);
}

.arsenal-border-gold {
  border: 1px solid rgba(156, 130, 74, 0.3);
}

/* Hover effects */
.arsenal-hover:hover {
  box-shadow: 0 0 15px var(--arsenal-red-glow);
  border-color: var(--arsenal-red);
  transition: all 0.2s ease;
}

/* Active tab underline */
.arsenal-tab-active {
  border-bottom: 2px solid var(--arsenal-red);
}

@theme inline {
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}

/* ============================================
   MICRO-ANIMATIONS & TRANSITIONS
   Premium fintech polish
   ============================================ */

/* Tab content fade-in */
.tab-content {
  animation: fadeInUp 0.25s ease-out;
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Subtle bounce for icons */
.animate-bounce-subtle {
  animation: bounceSoft 2s ease-in-out infinite;
}

@keyframes bounceSoft {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-4px);
  }
}

/* Card hover lift effect */
.card-hover {
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.card-hover:hover {
  transform: translateY(-2px);
  box-shadow: 0 4px 20px rgba(239, 1, 7, 0.15);
}

/* Progress bar smooth fill */
.progress-animated [data-state="indeterminate"] > div,
.progress-animated > div {
  transition: width 0.5s ease-out;
}

/* Number counting animation feel */
.stat-number {
  font-variant-numeric: tabular-nums;
  transition: all 0.3s ease-out;
}

/* Big number emphasis */
.big-number {
  font-size: 2.5rem;
  font-weight: 800;
  font-variant-numeric: tabular-nums;
  letter-spacing: -0.02em;
}

/* Goal celebration pulse */
@keyframes goalCelebration {
  0% {
    transform: scale(1);
  }
  50% {
    transform: scale(1.15);
  }
  100% {
    transform: scale(1);
  }
}

.goal-scored {
  animation: goalCelebration 0.5s ease-out;
}

/* Arsenal spinner */
.arsenal-spinner {
  width: 32px;
  height: 32px;
  border: 3px solid rgba(239, 1, 7, 0.2);
  border-top-color: #EF0107;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* Section header with red underline accent */
.section-header {
  font-size: 1.25rem;
  font-weight: 700;
  position: relative;
  padding-bottom: 0.5rem;
  margin-bottom: 1rem;
}

.section-header::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 40px;
  height: 2px;
  background: linear-gradient(90deg, #EF0107, transparent);
}

/* Status colors (W/D/L) */
.status-win {
  color: #22c55e;
}

.status-draw {
  color: #9C824A;
}

.status-loss {
  color: #EF0107;
}

/* ============================================
   MOBILE RESPONSIVENESS
   ============================================ */

/* Tab bar horizontal scroll on mobile */
.tab-bar-scroll {
  overflow-x: auto;
  scrollbar-width: none;
  -ms-overflow-style: none;
  -webkit-overflow-scrolling: touch;
}

.tab-bar-scroll::-webkit-scrollbar {
  display: none;
}

/* Stack cards on mobile */
@media (max-width: 640px) {
  .stat-cards-grid {
    grid-template-columns: 1fr !important;
  }

  .chart-container {
    min-height: 220px;
  }

  .big-number {
    font-size: 2rem;
  }

  /* Full width tables on mobile */
  .mobile-table-scroll {
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
  }

  .mobile-table-scroll table {
    min-width: 500px;
  }
}

@media (max-width: 768px) {
  .charts-grid {
    grid-template-columns: 1fr !important;
  }
}

/* ============================================
   TOAST CUSTOMIZATION (Sonner)
   ============================================ */

[data-sonner-toaster] [data-type="success"] {
  --normal-bg: #1a1a1a;
  --normal-border: rgba(34, 197, 94, 0.3);
  --normal-text: #22c55e;
}

[data-sonner-toaster] [data-type="error"] {
  --normal-bg: #1a1a1a;
  --normal-border: rgba(239, 1, 7, 0.3);
  --normal-text: #EF0107;
}

[data-sonner-toaster] [data-type="info"] {
  --normal-bg: #1a1a1a;
  --normal-border: rgba(156, 130, 74, 0.3);
  --normal-text: #9C824A;
}

/* ============================================
   VISUAL POLISH UTILITIES
   ============================================ */

/* Glass effect for overlays */
.glass-effect {
  background: rgba(26, 26, 26, 0.8);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

/* Gradient text for emphasis */
.gradient-text-arsenal {
  background: linear-gradient(135deg, #EF0107 0%, #9C824A 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Subtle divider line */
.divider-subtle {
  border-color: rgba(239, 1, 7, 0.1);
}

/* Focus ring for accessibility */
.focus-ring-arsenal:focus-visible {
  outline: 2px solid #EF0107;
  outline-offset: 2px;
}

/* Scrollbar styling for dark theme */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: #1a1a1a;
}

::-webkit-scrollbar-thumb {
  background: rgba(239, 1, 7, 0.3);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(239, 1, 7, 0.5);
}
